arguments.file_text:
.channel-item {
    display: flex;
    flex-direction: column;
    gap: 2px;
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    position: relative;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #9e9e9e;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    top: 8px;
    right: 12px;
    background-color: #e53935;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #3a3a3a;
    background: #2b2b2b;
    align-items: flex-end;
}

.message-input-area textarea {
    flex: 1;
    resize: none;
    border: 1px solid #4a4a4a;
    border-radius: 6px;
    background: #1e1e1e;
    color: #e0e0e0;
    padding: 8px 12px;
    font-family: inherit;
    font-size: 0.9rem;
    outline: none;
    transition: border-color 0.15s;
}

.message-input-area textarea:focus {
    border-color: #5c6bc0;
}

.send-btn {
    padding: 8px 18px;
    background: #5c6bc0;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background: #7986cb;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: rgba(255, 255, 255, 0.03);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.9rem;
    color: #d0d0d0;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border-radius: 12px;
    background: rgba(92, 107, 192, 0.2);
    border: 1px solid rgba(92, 107, 192, 0.3);
    color: #e0e0e0;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: rgba(92, 107, 192, 0.35);
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #7986cb;
    background: none;
    border: none;
    cursor: pointer;
    border-radius: 4px;
    transition: background-color 0.15s;
}

.thread-link:hover {
    background: rgba(121, 134, 203, 0.15);
    text-decoration: underline;
}

.hover-actions {
    position: absolute;
    top: -8px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2b2b2b;
    border: 1px solid #4a4a4a;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.hover-actions button {
    padding: 4px 8px;
    background: none;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
    transition: background-color 0.15s;
}

.hover-actions button:hover {
    background: rgba(255, 255, 255, 0.1);
}

.emoji-picker {
    position: absolute;
    top: -8px;
    right: 90px;
    display: flex;
    gap: 2px;
    background: #2b2b2b;
    border: 1px solid #4a4a4a;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.emoji-picker button {
    padding: 4px 6px;
    background: none;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1.1rem;
    transition: background-color 0.15s;
}

.emoji-picker button:hover {
    background: rgba(255, 255, 255, 0.1);
}

