@using Microsoft.AspNetCore.Components.Web.Virtualization
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h2># @ChannelName</h2>
        @if (!string.IsNullOrEmpty(ChannelDescription))
        {
            <span class="area-description">@ChannelDescription</span>
        }
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            var ts = ThreadSummaries.GetValueOrDefault(msg.Id);
            <MessageItem Message="msg"
                         ThreadSummary="ts"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonLabel="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private bool _loadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ScrollToBottom();
        }
    }

    private async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("eval", "document.querySelector('[data-scroll-bottom]')?.scrollTo(0, document.querySelector('[data-scroll-bottom]').scrollHeight)");
        }
        catch { /* component may have been disposed */ }
    }

    private async Task HandleScroll()
    {
        if (_loadingMore) return;

        try
        {
            var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[data-scroll-bottom]')?.scrollTop ?? 1");
            if (scrollTop < 50)
            {
                _loadingMore = true;
                StateHasChanged();
                await OnLoadMore.InvokeAsync();
                _loadingMore = false;
            }
        }
        catch { /* component may have been disposed */ }
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #1e1e1e;
    overflow: hidden;
}

.area-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    padding: 12px 16px;
    border-bottom: 1px solid #3a3a3a;
    background: #242424;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #e0e0e0;
}

.area-description {
    font-size: 0.85rem;
    color: #888;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: #888;
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #242424;
    border-left: 1px solid #3a3a3a;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #3a3a3a;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
    color: #e0e0e0;
}

.close-btn {
    background: none;
    border: none;
    color: #888;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.15s, color 0.15s;
}

.close-btn:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #e0e0e0;
}

.thread-root {
