arguments.file_text:
@page "/chat"
@using sv_7990b9df3b9c45f7a5ff41d2f4b93083.Components.Chat
@rendermode InteractiveServer
@inject IChatService ChatService
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnSelectChannel="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <MessageArea ChannelName="@_activeChannel.Name"
                         ChannelDescription="@_activeChannel.Description"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadOlderMessages" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnSendReply="SendThreadReply"
                         OnClose="CloseThread" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int _activeChannelId;
    private Channel? _activeChannel;

    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];
    private int _skip;
    private const int PageSize = 30;
    private bool _allLoaded;

    private bool _threadOpen;
    private int _threadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private CancellationTokenSource _cts = new();

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);

        _skip = 0;
        _allLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _skip = _messages.Count;

        await BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }

        CloseThreadSync();
    }

    private async Task LoadOlderMessages()
    {
        if (_allLoaded) return;

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _skip, PageSize);
        if (older.Count < PageSize) _allLoaded = true;

        _messages.InsertRange(0, older);
        _skip += older.Count;

        await BuildThreadSummaries();
    }

    private async Task BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        // Find messages that are replied to
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var replyCounts = _messages
            .Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value))
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyCounts)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
