+        _messages = await ChatService.GetMessagesAsync(_activeChannelId, 0, _skip);
+    }
+
+    private async Task OpenThread(int rootMessageId)
+    {
+        _threadRootId = rootMessageId;
+        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
+        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
+        _threadOpen = true;
+    }
+
+    private void CloseThread() => CloseThreadSync();
+
+    private void CloseThreadSync()
+    {
+        _threadOpen = false;
+        _threadRootMessage = null;
+        _threadReplies = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootId);
+        _threadReplies.Add(reply);
+        _messages.Add(reply);
+
+        // Update thread summary
+        _threadSummaries[_threadRootId] = new ThreadSummary(
+            _threadRootId,
+            _threadReplies.Count,
+            reply.SentAt);
+    }
